// ─── Logique d'insertion ──────────────────────────────────────────────────────

async function main() {
  const conn = await mysql.createConnection(DATABASE_URL);
  console.log(`[REDACTIO] Connexion à la base de données établie`);

  // Vérifier si la table existe
  const [tables] = await conn.execute("SHOW TABLES LIKE 'medical_terms'");
  if (tables.length === 0) {
    console.error("[REDACTIO] La table medical_terms n'existe pas. Exécutez la migration d'abord.");
    await conn.end();
    process.exit(1);
  }

  // Vider la table si elle contient déjà des données
  const [existing] = await conn.execute("SELECT COUNT(*) as count FROM medical_terms");
  const count = existing[0].count;
  if (count > 0) {
    console.log(`[REDACTIO] ${count} termes déjà en base. Suppression et réimport...`);
    await conn.execute("DELETE FROM medical_terms");
  }

  // Insertion par lots de 50
  const batchSize = 50;
  let inserted = 0;

  for (let i = 0; i < MEDICAL_TERMS.length; i += batchSize) {
    const batch = MEDICAL_TERMS.slice(i, i + batchSize);
    const values = batch.map(t => [
      t.term,
      t.category,
      JSON.stringify(t.synonyms || []),
      t.definition || null,
      t.source || "manuel",
      t.code || null,
      true,
      0,
    ]);

    await conn.query(
      `INSERT INTO medical_terms (term, category, synonyms, definition, source, code, active, usageCount)
       VALUES ?`,
      [values]
    );
    inserted += batch.length;
    console.log(`[REDACTIO] ${inserted}/${MEDICAL_TERMS.length} termes insérés...`);
  }

  console.log(`[REDACTIO] Import terminé : ${inserted} termes médicaux insérés en base.`);
  await conn.end();
}

main().catch(err => {
  console.error("[REDACTIO] Erreur lors de l'import :", err.message);
  process.exit(1);
});
